   146	  } else {
   147	    pktsize = RAW_PACKET_SIZE_BYTES(nsamps);
   148	  }   
   149	  for (i=0;i<cc;i++) {	
   150	    /* buff[i] points to the position in tx buffer where the payload to be sent is
   151	       buff2 points to the position in tx buffer where the packet header will be placed */
   152	    void *buff2 = (void*)(buff[i]-APP_HEADER_SIZE_BYTES-MAC_HEADER_SIZE_BYTES); 
   153	    
   154	    /* we don't want to ovewrite with the header info the previous tx buffer data so we store it*/
   155	    struct ether_header temp =  *(struct ether_header *)buff2;
   156	    int32_t temp0 = *(int32_t *)(buff2 + MAC_HEADER_SIZE_BYTES);
   157	    openair0_timestamp  temp1 = *(openair0_timestamp *)(buff2 + MAC_HEADER_SIZE_BYTES + sizeof(int32_t));
   158	    
   159	    bytes_sent = 0;
   160	    memcpy(buff2,(void*)&eth->ehd,MAC_HEADER_SIZE_BYTES);
   161	    *(int16_t *)(buff2 + MAC_HEADER_SIZE_BYTES + sizeof(int16_t))=1+(i<<1);
   162	    *(openair0_timestamp *)(buff2 + MAC_HEADER_SIZE_BYTES + sizeof(int32_t)) = timestamp;  
