   168	
   169	      /* Send packet */
   170	
   171	      bytes_sent += send(eth->sockfdd[cc % eth->num_fd],
   172				 buff2, 
   173				 pktsize,
   174				 sendto_flag);
   175	      if ( bytes_sent == -1) {
   176		eth->num_tx_errors++;
